import { Component, OnInit } from '@angular/core';
import { EquipsService } from '../../../services/equips.service';
import { EquipCategorias } from '../../../models/equip-categorias';

@Component({
  selector: 'app-ataque',
  templateUrl: './ataque.component.html',
  styleUrls: ['./ataque.component.css']
})
export class AtaqueComponent implements OnInit {
  subcategorias = [
    { nome: 'Armas', endpoint: 'arma' },
    { nome: 'Munição', endpoint: 'municao' },
    { nome: 'Armas Simples', endpoint: 'armas-simples' },
    { nome: 'Armas Marciais', endpoint: 'armas-marcial' },
    { nome: 'Armas Corpo a Corpo', endpoint: 'armas-corpo-a-corpo' },
    { nome: 'Armas a Distância', endpoint: 'armas-a-distancia' },
  ];

  equipamentos: EquipCategorias[] = []; // Lista dos equipamentos carregados
  popupEquipamento: EquipCategorias | null = null;// Para exibir no popup

  constructor(private equipsService: EquipsService) {}

  ngOnInit(): void {}

  carregarEquipamentos(endpoint: string): void {
    this.equipsService.getEquipamentosPorSubcategoria(endpoint).subscribe((resposta) => {
      console.log('Resposta da API:', resposta);
      this.equipamentos = resposta.equipment; // Acesse o array de equipamentos
      console.log('Equipamentos carregados:', this.equipamentos);
    });
  }

  exibirPopup(equipamento: EquipCategorias): void {
    this.popupEquipamento = equipamento;
  }

  fecharPopup(): void {
    this.popupEquipamento = null;
  }
}
